const phone = $input.first().json.attendee_phone;
const email = $input.first().json.attendee_email;

const filter = `or=(phone.eq.${encodeURIComponent(phone)},email.eq.${encodeURIComponent(email)})`;
const url = `http://supabase-kong-1:8000/rest/v1/leads?${filter}&limit=1`;

const response = await fetch(url, {
  headers: {
    'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
    'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json'
  }
});

const leads = await response.json();

if (leads.length > 0) {
  return [{ json: leads[0] }];
}

return [{ json: {} }];

const booking = $('Extract Attendee').first().json;
const baseUrl = 'http://supabase-kong-1:8000/rest/v1';
const headers = {
  'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

await fetch(`${baseUrl}/pipeline_logs`, {
  method: 'POST',
  headers,
  body: JSON.stringify({
    event: 'booking_no_lead_match',
    component: 'cal_com',
    details: JSON.stringify({
      booking_time: booking.booking_start,
      attendee_email: booking.attendee_email,
      attendee_name: booking.attendee_name,
      event_type: booking.booking_title
    })
  })
});

return [{ json: { matched: false, email: booking.attendee_email } }];

const lead = $('Match Lead').first().json;
const booking = $('Extract Attendee').first().json;
const baseUrl = 'http://supabase-kong-1:8000/rest/v1';
const headers = {
  'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

await fetch(`${baseUrl}/pipeline_logs`, {
  method: 'POST',
  headers,
  body: JSON.stringify({
    lead_id: lead.id,
    event: 'double_booking_prevented',
    component: 'cal_com',
    details: JSON.stringify({
      existing_booking: lead.call_scheduled_at,
      attempted_booking: booking.booking_start,
      attendee_email: booking.attendee_email,
      lead_name: lead.name
    })
  })
});

return [{ json: { prevented: true, lead_id: lead.id, lead_name: lead.name } }];

const lead = $('Match Lead').first().json;
const booking = $('Extract Attendee').first().json;
const leadId = lead.id;
const baseUrl = 'http://supabase-kong-1:8000/rest/v1';
const headers = {
  'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

// 1. Atomic update: only succeeds if lead is NOT already call_scheduled
//    This prevents race conditions when concurrent webhooks arrive
const updateRes = await fetch(
  `${baseUrl}/leads?id=eq.${leadId}&status=neq.call_scheduled`,
  {
    method: 'PATCH',
    headers,
    body: JSON.stringify({
      status: 'call_scheduled',
      call_scheduled_at: booking.booking_start
    })
  }
);
const updated = await updateRes.json();

// If 0 rows returned, another request already set call_scheduled (race condition)
if (!updated || updated.length === 0) {
  await fetch(`${baseUrl}/pipeline_logs`, {
    method: 'POST',
    headers,
    body: JSON.stringify({
      lead_id: leadId,
      event: 'double_booking_prevented',
      component: 'cal_com',
      details: JSON.stringify({
        reason: 'race_condition_guard',
        attempted_booking: booking.booking_start,
        attendee_email: booking.attendee_email
      })
    })
  });
  return [{ json: { id: leadId, prevented: true, reason: 'race_condition' } }];
}

// 2. Log booking event
await fetch(`${baseUrl}/pipeline_logs`, {
  method: 'POST',
  headers,
  body: JSON.stringify({
    lead_id: leadId,
    event: 'booking_created',
    component: 'cal_com',
    details: JSON.stringify({
      booking_time: booking.booking_start,
      attendee_email: booking.attendee_email,
      event_type: booking.booking_title
    })
  })
});

return [{ json: updated[0] || { id: leadId, status: 'call_scheduled' } }];
